import json
import re

config = json.load(open('config.json'))
schema = json.load(open('schema.json'))

errors = []

# Check required fields
if 'required' in schema:
    for field in schema['required']:
        if field not in config:
            errors.append(f'Missing required field: {field}')

# Validate name field
if 'name' in config:
    if not isinstance(config['name'], str):
        errors.append('name must be a string')
    elif len(config['name']) < 1:
        errors.append('name must have minLength of 1')
else:
    errors.append('name field is missing')

# Validate version field
if 'version' in config:
    if not isinstance(config['version'], str):
        errors.append('version must be a string')
    elif not re.match(r'^[0-9]+\.[0-9]+\.[0-9]+$', config['version']):
        errors.append(f'version does not match pattern: {config[\"version\"]}')
else:
    errors.append('version field is missing')

# Check for extra properties not in schema
schema_props = set(schema.get('properties', {}).keys())
config_keys = set(config.keys())
if not schema.get('additionalProperties', False):
    extra_keys = config_keys - schema_props
    if extra_keys:
        errors.append(f'Extra properties not allowed: {extra_keys}')

if errors:
    print('✗ Validation failed:')
    for error in errors:
        print(f'  - {error}')
    exit(1)
else:
    print('✓ config.json is valid against schema.json')
    print(f'  - name: {config[\"name\"]}')
    print(f'  - version: {config[\"version\"]}')
    exit(0)
"
